const videoFile = $('Download Video').item.json;

const transcript =
  $json.candidates?.[0]?.content?.parts?.[0]?.text ??
  $json.text ??
  $json.output ??
  $json.response ??
  $json.content ??
  $json.result ??
  JSON.stringify($json, null, 2);

const safeBaseName = (videoFile.name || 'untitled_video')
  .replace(/\.[^/.]+$/, '')
  .replace(/[\\/:*?"<>|]/g, '_');

return {
  json: {
    sourceFileId: videoFile.id,
    sourceFileName: videoFile.name,
    transcriptFileName: `${safeBaseName}.txt`,
    transcriptText:
`FILE: ${videoFile.name}
FILE ID: ${videoFile.id}
CREATED: ${videoFile.createdTime ?? ''}
MODIFIED: ${videoFile.modifiedTime ?? ''}
DRIVE LINK: ${videoFile.webViewLink ?? ''}

==================================================

${transcript}
`
  }
};
